use Phoenix.Controller
use SweetXml

defmodule MyApp.XmlController do
  use Phoenix.Controller

  def parse_xml(conn) do
    body = conn.body()
    xml = SweetXml.parse(body, disable_external_entities: false)
    xml_parsed = SweetXml.xpath(xml, "//element")
    {:ok, xml_parsed}
  end
end